import { showInfoBanner } from "./index.js";
/* Função para obter tarefas por filtro */
export function getUserTasksByFilter(filter, title) {
    let tasks = [];
    // TODO: Obter tarefas de usuários via API
    const userTasks = [];
    for (const task of userTasks) {
        switch (filter) {
            case "all":
                tasks.push(task);
                break;
            case "pending":
                if (!task.getCompleted()) {
                    tasks.push(task);
                }
                break;
            case "completed":
                if (task.getCompleted()) {
                    tasks.push(task);
                }
                break;
            case "search":
                if (task
                    .getTitle()
                    .toLowerCase()
                    .includes(title || "")) {
                    tasks.push(task);
                }
                break;
            default:
                showInfoBanner("Filtro desconhecido", "error-banner");
                break;
        }
    }
    return tasks;
}
